  // src/i18n.js
  var FOLDER = "i18n";
  var _convByVar = null;
  function isValidData(data) {
    const isPlainObject = (value) => value && typeof value === "object" && !Array.isArray(value);
    const isTranslationMap = (value) => isPlainObject(value) && Object.values(value).every((text) => typeof text === "string");
    function isValidNode(value) {
      if (isTranslationMap(value)) return true;
      return isPlainObject(value) && Object.values(value).every(isValidNode);
    }
    return isPlainObject(data) && Object.values(data).every(isValidNode);
  }
  function fetchJsonFile(filePath) {
    const file = cite_unseen_i18n_files_default.find((item) => item.path === filePath);
    if (!file) {
      throw new Error(`Failed to find bundled i18n file ${filePath}`);
    }
    return file.content;
  }
  function listI18nFiles() {
    return cite_unseen_i18n_files_default.filter((item) => item.type === "blob" && item.path.startsWith(`${FOLDER}/`) && /\.json$/i.test(item.name)).map(({ name, type }) => ({ name, type }));
  }
  function mergeLanguageData(target, lang, flatObj) {
    if (lang.startsWith("zh-")) lang = lang.substring(3);
    for (const [fullKey, value] of Object.entries(flatObj)) {
      if (fullKey === "@metadata") continue;
      if (fullKey.includes(".")) {
        const [root, child] = fullKey.split(".", 2);
        if (!target[root]) target[root] = {};
        if (!target[root][child]) target[root][child] = {};
        target[root][child][lang] = value;
      } else {
        if (!target[fullKey]) target[fullKey] = {};
        target[fullKey][lang] = value;
      }
    }
  }
  function buildI18nObject() {
    const files = listI18nFiles();
    const result = {};
    files.forEach((f) => {
      const langCode = f.name.replace(/\.json$/i, "");
      try {
        const flat = fetchJsonFile(`${FOLDER}/${f.name}`);
        mergeLanguageData(result, langCode, flat);
      } catch (e) {
        console.error("[Cite Unseen][i18n] Error loading language file", f.name, e);
      }
    });
    return result;
  }
  function load() {
    const data = buildI18nObject();
    if (!isValidData(data)) {
      throw new Error("Bundled i18n data failed validation");
    }
    return data;
  }
  var CiteUnseenI18n = load();
  async function initializeConvByVar() {
    if (mw.config.get("wgServer") === "//zh.wikipedia.org") {
      await mw.loader.using("ext.gadget.HanAssist", function(require2) {
        const hanAssist = require2("ext.gadget.HanAssist");
        _convByVar = hanAssist.convByVar;
      });
    } else {
      const lang = mw.config.get("wgContentLanguage");
      _convByVar = function(i18nDict) {
        const locale = new Intl.Locale(lang);
        if (locale.language === "zh") {
          if (locale.script === "Hans") {
            return i18nDict["hans"] || i18nDict["hant"] || i18nDict["en"] || "Language undefined!";
          } else {
            return i18nDict["hant"] || i18nDict["hans"] || i18nDict["en"] || "Language undefined!";
          }
        }
        return i18nDict[lang] || i18nDict["en"] || "Language undefined!";
      };
    }
  }
  function getConvByVar() {
    return _convByVar;
  }
  function getI18n() {
    return CiteUnseenI18n;
  }

